from collections import defaultdict

def train_wordpiece(corpus: list[str], num_merges: int) -> tuple[list[tuple], dict]:
    # Initialize: first char as-is, rest prefixed with ##
    vocab = defaultdict(int)
    for word in corpus:
        if not word:
            continue
        symbols = [word[0]] + ['##' + c for c in word[1:]]
        vocab[tuple(symbols)] += 1

    def get_symbol_freqs(vocab):
        freqs = defaultdict(int)
        for symbols, cnt in vocab.items():
            for s in symbols:
                freqs[s] += cnt
        return freqs

    def get_pair_freqs(vocab):
        pairs = defaultdict(int)
        for symbols, cnt in vocab.items():
            for i in range(len(symbols)-1):
                pairs[(symbols[i], symbols[i+1])] += cnt
        return pairs

    def merge_pair(pair, vocab):
        new_vocab = defaultdict(int)
        a, b = pair
        merged = a + b.lstrip('#') if b.startswith('##') else a + b
        for symbols, cnt in vocab.items():
            new_syms = []
            i = 0
            while i < len(symbols):
                if i < len(symbols)-1 and symbols[i]==a and symbols[i+1]==b:
                    new_syms.append(merged)
                    i += 2
                else:
                    new_syms.append(symbols[i])
                    i += 1
            new_vocab[tuple(new_syms)] += cnt
        return new_vocab

    merges = []
    for _ in range(num_merges):
        sym_freqs = get_symbol_freqs(vocab)
        pair_freqs = get_pair_freqs(vocab)
        if not pair_freqs:
            break
        best_pair = max(
            pair_freqs,
            key=lambda p: pair_freqs[p] / (sym_freqs[p[0]] * sym_freqs[p[1]] + 1e-12)
        )
        merges.append(best_pair)
        vocab = merge_pair(best_pair, vocab)
    return merges, dict(vocab)
